            "})]}),showPublishModal&&/*#__PURE__*/_jsx("div",{style:{position:'fixed',top:0,left:0,right:0,bottom:0,backgroundColor:'rgba(0, 0, 0, 0.7)',display:'flex',justifyContent:'center',alignItems:'center',zIndex:1000},children:/*#__PURE__*/_jsxs("div",{style:{backgroundColor:theme==='light'?'#fff':'#2d2d2d',borderRadius:'12px',padding:'30px',maxWidth:'500px',width:'90%',boxShadow:'0 10px 40px rgba(0, 0, 0, 0.3)'},children:[/*#__PURE__*/_jsxs("div",{style:{textAlign:'center',marginBottom:'20px'},children:[/*#__PURE__*/_jsx("div",{style:{fontSize:'48px',marginBottom:'15px',color:'#4CAF50'},children:"✓"}),/*#__PURE__*/_jsx("h2",{style:{margin:'0 0 10px 0',color:theme==='light'?'#333':'#fff',fontSize:'24px'},children:"Successfully Published!"}),/*#__PURE__*/_jsx("p",{style:{margin:0,color:theme==='light'?'#666':'#aaa',fontSize:'14px'},children:"Your project is now live on the web"})]}),/*#__PURE__*/_jsxs("div",{style:{backgroundColor:theme==='light'?'#f5f5f5':'#1e1e1e',padding:'15px',borderRadius:'8px',marginBottom:'20px',display:'flex',alignItems:'center',gap:'10px'},children:[/*#__PURE__*/_jsx("input",{type:"text",value:publishedUrl,readOnly:true,style:{flex:1,padding:'10px',border:"1px solid ".concat(theme==='light'?'#ddd':'#444'),borderRadius:'6px',fontSize:'13px',backgroundColor:theme==='light'?'#fff':'#2d2d2d',color:theme==='light'?'#333':'#ddd',outline:'none'}}),/*#__PURE__*/_jsx("button",{onClick:copyToClipboard,style:{padding:'10px 20px',backgroundColor:'#2196F3',color:'white',border:'none',borderRadius:'6px',cursor:'pointer',fontSize:'13px',fontWeight:'bold',whiteSpace:'nowrap'},children:"Copy"})]}),/*#__PURE__*/_jsxs("div",{style:{display:'flex',gap:'10px',justifyContent:'center'},children:[/*#__PURE__*/_jsx("button",{onClick:()=>{window.open(publishedUrl,'_blank');},style:{flex:1,padding:'12px 24px',backgroundColor:'#4CAF50',color:'white',border:'none',borderRadius:'8px',cursor:'pointer',fontSize:'14px',fontWeight:'bold'},children:"Go Live"}),/*#__PUR