        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.7)',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          zIndex: 1000,
          overflowY: 'auto',
          padding: '20px'
        }}>
          <div style={{
            backgroundColor: theme === 'light' ? '#fff' : '#2d2d2d',
            borderRadius: '12px',
            padding: '30px',
            maxWidth: '600px',
            width: '90%',
            boxShadow: '0 10px 40px rgba(0, 0, 0, 0.3)',
            maxHeight: '90vh',
            overflowY: 'auto',
            margin: 'auto'
          }}>
            <h2 style={{
              margin: '0 0 20px 0',
              color: theme === 'light' ? '#333' : '#fff',
              fontSize: '24px',
              textAlign: 'center'
            }}>
              Choose Deployment Method
            </h2>

            {/* GitHub CI/CD Option */}
            <div 
              onClick={handleGitHubDeploy}
              style={{
                backgroundColor: theme === 'light' ? '#f8f9fa' : '#1e1e1e',
                border: `2px solid ${theme === 'light' ? '#e0e0e0' : '#444'}`,
                borderRadius: '10px',
                padding: '20px',
                marginBottom: '15px',
                cursor: 'pointer',
                transition: 'all 0.3s ease',
                position: 'relative'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.borderColor = '#2196F3';
                e.currentTarget.style.transform = 'translateY(-2px)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.borderColor = theme === 'light' ? '#e0e0e0' : '#444';
                e.currentTarget.style.transform = 'translateY(0)';
              }}
            >
              <div style={{
                position: 'absolute',
                top: '10px',
                right: '10px',
                backgroundColor: '#FFC107',
                color: '#000',
                padding: '2px 8px',
                borderRadius: '4px',
                fontSize: '10px',
                fontWeight: 'bold'
              }}>
                COMING SOON
              </div>
              <h3 style={{
                margin: '0 0 10px 0',
                color: theme === 'light' ? '#333' : '#fff',
                fontSize: '18px'
              }}>
                Publish via GitHub CI/CD Pipeline
              </h3>
              <p style={{
                margin: '0',
                color: theme === 'light' ? '#666' : '#aaa',
                fontSize: '13px',
                lineHeight: '1.6'
              }}>
                <strong>Technical Workflow:</strong><br/>
                1. <strong>Version Control Integration:</strong> Your code will be pushed to a GitHub repository with proper branch management<br/>
                2. <strong>CI/CD Pipeline Setup:</strong> GitHub Actions will be configured to automatically trigger on code commits to main branch<br/>
                3. <strong>Build & Test Automation:</strong> Pipeline will validate, build, and run automated tests on your codebase<br/>
                4. <strong>Continuous Deployment:</strong> Successful builds will be automatically deployed to production server with zero-downtime deployment strategies<br/>
                5. <strong>Webhook Integration:</strong> GitHub webhooks will notify deployment server on push events for instant updates<br/>
                6. <strong>Environment Management:</strong> Separate staging and production environments with environment-specific configurations
              </p>
            </div>

            {/* Direct Server Deploy Option */}
            <div 
              onClick={handleDirectDeploy}
              style={{
                backgroundColor: theme === 'light' ? '#f8f9fa' : '#1e1e1e',
                border: `2px solid ${theme === 'light' ? '#e0e0e0' : '#444'}`,
                borderRadius: '10px',
                padding: '20px',
                marginBottom: '20px',
                cursor: 'pointer',
                transition: 'all 0.3s ease'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.borderColor = '#4CAF50';
                e.currentTarget.style.transform = 'translateY(-2px)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.borderColor = theme === 'light' ? '#e0e0e0' : '#444';
                e.currentTarget.style.transform = 'translateY(0)';
              }}
            >
              <h3 style={{
                margin: '0 0 10px 0',
                color: theme === 'light' ? '#333' : '#fff',
                fontSize: '18px'
              }}>
                Deploy on Dedicated Server (Quick Deploy)
              </h3>
              <p style={{
                margin: '0',
                color: theme === 'light' ? '#666' : '#aaa',
                fontSize: '13px',
                lineHeight: '1.6'
              }}>
                <strong>Technical Workflow:</strong><br/>
                1. <strong>Code Bundling:</strong> HTML, CSS, and JavaScript files are merged into a single optimized bundle<br/>
                2. <strong>Server Upload:</strong> Bundled code is directly uploaded to our dedicated hosting server via secure API<br/>
                3. <strong>Static File Serving:</strong> Express.js serves your project as static files with proper MIME types and caching headers<br/>
                4. <strong>Instant Deployment:</strong> No build process required - your project goes live immediately with a unique URL<br/>
                5. <strong>Hot Updates:</strong> Re-publish feature allows instant updates to the same URL without downtime
              </p>
            </div>

            <button
              onClick={() => setShowDeploymentOptions(false)}
              style={{
                width: '100%',
                padding: '12px',
                backgroundColor: theme === 'light' ? '#f0f0f0' : '#444',
                color: theme === 'light' ? '#333' : '#fff',
                border: 'none',
                borderRadius: '8px',
                cursor: 'pointer',
                fontSize: '14px',
                fontWeight: 'bold'
              }}
            >
              Cancel
            </button>
          </div>
        </div>
      )}
      
      {/* Confirm Deploy Modal */}
      {showConfirmDeploy && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.7)',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          zIndex: 1001
        }}>
          <div style={{
            backgroundColor: theme === 'light' ? '#fff' : '#2d2d2d',
            borderRadius: '12px',
            padding: '30px',
            maxWidth: '450px',
            width: '90%',
            boxShadow: '0 10px 40px rgba(0, 0, 0, 0.3)'
          }}>
            <h2 style={{
              margin: '0 0 15px 0',
              color: theme === 'light' ? '#333' : '#fff',
              fontSize: '22px',
              textAlign: 'center'
            }}>
              {isPublished ? 'Re-Publish Project' : 'Confirm Deployment'}
            </h2>
            <p style={{
              margin: '0 0 20px 0',
              color: theme === 'light' ? '#666' : '#aaa',
              fontSize: '14px',
              lineHeight: '1.6',
              textAlign: 'center'
            }}>
              {isPublished 
                ? 'Update your existing project with the latest changes:' 
                : 'Enter a custom name for your project URL:'}
            </p>
            
            <div style={{
              marginBottom: '10px'
            }}>
              <label style={{
                display: 'block',
                marginBottom: '8px',
                color: theme === 'light' ? '#666' : '#aaa',
                fontSize: '13px',
                fontWeight: 'bold'
              }}>
                Project Name/Slug:
              </label>
              <input
                type="text"
                value={customProjectSlug}
                onChange={(e) => setCustomProjectSlug(e.target.value)}
                placeholder="my-awesome-project"
                readOnly={isPublished && savedProjectId ? true : false}
                style={{
                  width: '100%',
                  padding: '12px',
                  border: `1px solid ${theme === 'light' ? '#ddd' : '#444'}`,
                  borderRadius: '8px',
                  fontSize: '14px',
                  backgroundColor: isPublished && savedProjectId 
                    ? (theme === 'light' ? '#f5f5f5' : '#2a2a2a')
                    : (theme === 'light' ? '#fff' : '#1e1e1e'),
                  color: theme === 'light' ? '#333' : '#ddd',
                  outline: 'none',
                  boxSizing: 'border-box',
                  cursor: isPublished && savedProjectId ? 'not-allowed' : 'text'
                }}
              />
              <p style={{
                margin: '8px 0 0 0',
                color: theme === 'light' ? '#999' : '#666',
                fontSize: '12px'
              }}>
                Preview: {API_URL}/{customProjectSlug || 'your-project-name'}
              </p>
            </div>

            <p style={{
              margin: '0 0 25px 0',
              color: theme === 'light' ? '#666' : '#aaa',
              fontSize: '13px',
              lineHeight: '1.5',
              textAlign: 'center'
            }}>
              {isPublished && savedProjectId ? (
                <>
                  <strong>Note:</strong> This will update your existing project at the same URL.
                </>
              ) : (
                <>
                  <strong>Note:</strong> Only letters, numbers, hyphens, and underscores are allowed.
                  <br/>
                  This will make your project publicly accessible.
                </>
              )}
            </p>
            
            <div style={{
              display: 'flex',
              gap: '10px'
            }}>
              <button
                onClick={() => {
                  setShowConfirmDeploy(false);
                  setShowDeploymentOptions(true);
                  setCustomProjectSlug('');
                }}
                style={{
                  flex: 1,
                  padding: '12px',
                  backgroundColor: theme === 'light' ? '#f0f0f0' : '#444',
                  color: theme === 'light' ? '#333' : '#fff',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontSize: '14px',
                  fontWeight: 'bold'
                }}
              >
                Cancel
              </button>
              <button
                onClick={confirmAndDeploy}
                style={{
                  flex: 1,
                  padding: '12px',
                  backgroundColor: '#4CAF50',
                  color: 'white',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontSize: '14px',
                  fontWeight: 'bold'
                }}
              >
                {isPublished ? 'Update Project' : 'Yes, Deploy'}
              </button>
            </div>
          </div>
        </div>
      )}
      
      {/* Full Screen Loader during Publishing */}
      {isPublishing && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.8)',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          alignItems: 'center',
          zIndex: 9999
        }}>
          <div style={{
            width: '60px',
            height: '60px',
            border: '5px solid #f3f3f3',
            borderTop: '5px solid #9C27B0',
            borderRadius: '50%',
            animation: 'spin 1s linear infinite'
          }}></div>
          <p style={{
            color: 'white',
            marginTop: '20px',
            fontSize: '18px',
            fontWeight: 'bold'
          }}>
            Publishing your project...
          </p>
          <p style={{
            color: '#ccc',
            marginTop: '5px',
            fontSize: '14px'
          }}>
            Please wait, this may take a few moments
          </p>
          <style>
            {`
              @keyframes spin {
                0% { transform: rotate(0deg); }
                100% { transform: rotate(360deg); }
              }
            `}
          </style>
        </div>
      )}
      
      {/* Publish Success Modal */}
      {showPublishModal && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.7)',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          zIndex: 1000
        }}>
          <div style={{
            backgroundColor: theme === 'light' ? '#fff' : '#2d2d2d',
            borderRadius: '12px',
            padding: '30px',
            maxWidth: '500px',
            width: '90%',
            boxShadow: '0 10px 40px rgba(0, 0, 0, 0.3)'
          }}>
            <div style={{
              textAlign: 'center',
              marginBottom: '20px'
            }}>
              <div style={{
                fontSize: '48px',
                marginBottom: '15px',
                color: '#4CAF50'
              }}>
                ✓
              </div>
              <h2 style={{
                margin: '0 0 10px 0',
                color: theme === 'light' ? '#333' : '#fff',
                fontSize: '24px'
              }}>
                Successfully Published!
              </h2>
              <p style={{
                margin: 0,
                color: theme === 'light' ? '#666' : '#aaa',
                fontSize: '14px'
              }}>
                Your project is now live on the web
              </p>
            </div>

            <div style={{
              backgroundColor: theme === 'light' ? '#f5f5f5' : '#1e1e1e',
              padding: '15px',
              borderRadius: '8px',
              marginBottom: '20px',
              display: 'flex',
              alignItems: 'center',
              gap: '10px'
            }}>
              <input
                type="text"
                value={publishedUrl}
                readOnly
                style={{
                  flex: 1,
                  padding: '10px',
                  border: `1px solid ${theme === 'light' ? '#ddd' : '#444'}`,
                  borderRadius: '6px',
                  fontSize: '13px',
                  backgroundColor: theme === 'light' ? '#fff' : '#2d2d2d',
                  color: theme === 'light' ? '#333' : '#ddd',
                  outline: 'none'
                }}
              />
              <button
                onClick={copyToClipboard}
                style={{
                  padding: '10px 20px',
                  backgroundColor: '#2196F3',
                  color: 'white',
                  border: 'none',
                  borderRadius: '6px',
                  cursor: 'pointer',
                  fontSize: '13px',
                  fontWeight: 'bold',
                  whiteSpace: 'nowrap'
                }}
              >
                Copy
              </button>
            </div>

            <div style={{
              display: 'flex',
              gap: '10px',
              justifyContent: 'center'
            }}>
              <button
                onClick={() => {
                  window.open(publishedUrl, '_blank');
                }}
                style={{
                  flex: 1,
                  padding: '12px 24px',
                  backgroundColor: '#4CAF50',
                  color: 'white',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontSize: '14px',
                  fontWeight: 'bold'
                }}
              >
                Go Live
              </button>
              <button
                onClick={closePublishModal}
                style={{
                  flex: 1,
                  padding: '12px 24px',
                  backgroundColor: theme === 'light' ? '#f0f0f0' : '#444',
                  color: theme === 'light' ? '#333' : '#fff',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontSize: '14px',
                  fontWeight: 'bold'
                }}
              >
                OK
              </button>
            </div>
          </div>
        </div>
      )}
      
      {/* Auth Modal */}
      {showAuthModal && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.9)',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          zIndex: 10000,
          overflowY: 'auto',
          padding: '20px'
        }}>
          <div style={{ position: 'relative', width: '100%', maxWidth: '450px' }}>
            <button
              onClick={() => setShowAuthModal(false)}
              style={{
                position: 'absolute',
                top: '-10px',
                right: '-10px',
                width: '40px',
                height: '40px',
                borderRadius: '50%',
                backgroundColor: '#f44336',
                color: 'white',
                border: 'none',
                fontSize: '20px',
                cursor: 'pointer',
                zIndex: 10001
              }}
            >
              x
            </button>
            <Auth onLoginSuccess={handleLoginSuccess} theme={theme} />
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
